import { signal } from "@preact/signals";
import { QuestionData, SingleLineQuestionData, QuestionnaireData, MultiLineQuestionData } from "./questionnaire"

export type Response = {
	content: string
}

export function Response(content: string): Response {
	return {
		content: content
	}
}

type None = 'none'

type SingleLineChoice = None | number;
type MultiLineChoice = { [questionIndex: number]: SingleLineChoice };

type Choice<QD> = QD extends SingleLineQuestionData ? SingleLineChoice : (QD extends MultiLineQuestionData ? MultiLineChoice : never);

export type Question<QD extends QuestionData> = {
	content: QD,
	choice: Choice<QD>
}

export type AQuestion = Question<QuestionData>

export function Question<QD extends QuestionData>(content: QD): Question<QD> {
	let choice;
	switch(content.kind) {
		case "singleLine": {
			choice = 'none';
		}
		case "multiLine": {
			choice = {};
		}
	}
	return {
		content: content,
		choice: choice
	}
}

export type State = {
	questionnaire: { [id: number]: AQuestion }
}

export function State(questionnaire: Question<QuestionData>[]): State {
	let qMap = Object.fromEntries(questionnaire.map(q => [q.content.id, q]))
	return {
		questionnaire: qMap
	}
}

export const state = signal(
	State(
		QuestionnaireData.map(q => Question(q))
	)
);

type SingleLineAnswer = {
	kind: 'answer';
	questionId: number;
	answerIndex: number;
}

type MultiLineAnswer = {
	kind: 'multiLineAnswer';
	questionId: number;
	qrIndex: [number, number]
}

export type Event = SingleLineAnswer | MultiLineAnswer;

export function dispatch(event: Event) {
	let newState: State;
	switch(event.kind) {
		case 'answer': {
			let question = state.value.questionnaire[event.questionId]
			let newQuestion: Question<QuestionData> = {
				...question,
				choice: event.answerIndex,
			}
			console.log(newQuestion);
			newState = {
				questionnaire: {
					...state.value.questionnaire,
					[question.content.id]: newQuestion
				}
			}
			break;
		}
		case 'multiLineAnswer': {
			let question = state.value.questionnaire[event.questionId] as Question<MultiLineQuestionData>
			let newChoice = {
				...question.choice,
				[event.qrIndex[0]]: event.qrIndex[1]
			}
			let newQuestion: Question<MultiLineQuestionData> = {
				...question,
				choice: newChoice
			}
			newState = {
				questionnaire: {
					...state.value.questionnaire,
					[question.content.id]: newQuestion
				}
			}
		}
	}
	state.value = newState;
}